// import { render } from "react-dom";
import Gallery from "react-photo-gallery";
import Carousel, { Modal, ModalGateway } from "react-images";

// Import the image using a relative path
import Merc0 from './images/Merc_0.jpeg';
import Merc1 from './images/Merc1.png';
import Merc2 from './images/Merc2.png';
import Merc3 from './images/Merc3.png';
import Merc4 from './images/Merc4.png';
