import Merc19 from './images/Merc19.png';
import Merc20 from './images/Merc20.png';
import Merc21 from './images/Merc21.png';
import Merc22 from './images/Merc22.png';
import Merc23 from './images/Merc23.png';

import CAOE0 from './images/CAOE0.jpg';
// import CAOE1 from './images/CAOE1.jpg';
import CAOE2 from './images/CAOE2.png';
import CAOE3 from './images/CAOE3.png';

import Regal1 from './images/Regal1.jpg';
import Regal2 from './images/Regal2.jpg';

import SI1 from './images/SI1.jpg';


export default function Projects() {
  // Move useState and useCallback inside the functional component
  const [currentImage, setCurrentImage] = useState(0);
  const [viewerIsOpen, setViewerIsOpen] = useState(false);

  const openLightbox = useCallback((event, {index }) => {
    setCurrentImage(index);
    setViewerIsOpen(true);
  }, []);

  const closeLightbox = () => {
    setCurrentImage(0);
    setViewerIsOpen(false);
  };

  // Define photos with local paths
  const mercPhotos = [
    {
      src: Merc0,
      width: 16,
      height: 9,
      style: { paddingBottom: '50px', paddingRight: '1px' }
    },
    {
      src: Merc1,
      width: 16,
      height: 9,
      style: { paddingBottom: '50px', paddingRight: '1px' }
