            <Modal onClose={closeLightbox}>
              <Carousel
                currentIndex={currentImage}
                views={mercPhotos.map(x => ({
                  ...x,
                  srcset: x.srcSet,
                  caption: x.title
                }))}
              />
            </Modal>
          ) : null}
        </ModalGateway>
      </div>

      <div className="projects-container">
        <h1>U.S. Department of Homeland Security</h1>
        <p>Collaborated closely with technology and operations experts to analyze over 1000 data points
        and design resilient TSA airport checkpoint systems, resulting in a 15% decrease in wait times.</p>
        <Gallery photos={CAOEPhotos} onClick={openLightbox} />
        <ModalGateway>
          {viewerIsOpen ? (
            <Modal onClose={closeLightbox}>
              <Carousel
                currentIndex={currentImage}
                views={mercPhotos.map(x => ({
                  ...x,
                  srcset: x.srcSet,
                  caption: x.title
                }))}
              />
            </Modal>
          ) : null}
        </ModalGateway>
      </div>

      <div className="projects-container">
        <h1>Regal Boats</h1>
        <p>Process Improvement at a Regal Manufacturing Facility. 
          Implementation of various methodologies such as Six Sigma and Lean, along with tools like Excel, Minitab, Python, and Simio Simulation models to
          increase operational efficiency, improve layout designs, and comply with ISO 9001 requirements.</p>
        <Gallery photos={regalPhotos} onClick={openLightbox} />
        <ModalGateway>
          {viewerIsOpen ? (
            <Modal onClose={closeLightbox}>
              <Carousel
                currentIndex={currentImage}
